classDiagram(name = "LibraryManagement") {
    val library = classOf(name = "Library") {
        attribute(name = "name", type = "String")
    }
    val book = classOf(name = "Book") {
        attribute(name = "title", type = "String")
        attribute(name = "author", type = "String")
        attribute(name = "isbn", type = "String")
    }
    val member = classOf(name = "Member") {
        attribute(name = "memberNumber", type = "Int")
        attribute(name = "name", type = "String")
    }
    val loan = classOf(name = "Loan") {
        attribute(name = "loanDate", type = "Date")
        attribute(name = "returnDate", type = "Date")
        operation(name = "extend") { returns(typeName = "Unit") }
    }

    association(source = library, target = book) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "books" }
    }
    association(source = member, target = loan) {
        source { multiplicity(spec = "1"); role = "loans" }
        target { multiplicity(spec = "0..*") }
    }
    association(source = book, target = loan) {
        source { multiplicity(spec = "1"); role = "loanHistory" }
        target { multiplicity(spec = "0..*") }
    }
}

classDiagram(name = "ParkingGarageModel") {
    val parkingGarage = classOf(name = "ParkingGarage") {
        attribute(name = "name", type = "String")
        operation(name = "issueTicket") { returns(typeName = "Ticket") }
        operation(name = "findAvailableSpot") { returns(typeName = "ParkingSpot") }
    }

    val level = classOf(name = "Level") {
        attribute(name = "levelNumber", type = "Int")
    }

    val parkingSpot = classOf(name = "ParkingSpot") {
        attribute(name = "spotId", type = "String")
        attribute(name = "type", type = "String", isReadOnly = true) // e.g., "regular", "disabled", "electric charging"
    }

    val ticket = classOf(name = "Ticket") {
        attribute(name = "ticketId", type = "String")
        attribute(name = "entryTime", type = "DateTime")
        attribute(name = "exitTime", type = "DateTime") // Nullable in implementation, not explicitly optional in DSL
        operation(name = "calculateFee") { returns(typeName = "Double") }
    }

    association(source = parkingGarage, target = level) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "levels" } // A ParkingGarage has 1 to many Levels
    }

    association(source = level, target = parkingSpot) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "parkingSpots" } // A Level has 1 to many ParkingSpots
    }

    association(source = parkingSpot, target = ticket) {
        source { multiplicity(spec = "0..1"); role = "occupiedBy" } // A ParkingSpot is occupied by at most one Ticket
        target { multiplicity(spec = "0..1"); role = "assignedTo" } // A Ticket is assigned to at most one ParkingSpot
    }
}

