classDiagram(name = "CookbookModel") {
    val digitalCookbook = classOf(name = "DigitalCookbook") {
        // No explicit attributes mentioned
    }
    val recipe = classOf(name = "Recipe") {
        attribute(name = "title", type = "String")
        attribute(name = "preparationTime", type = "Int")
    }
    val ingredientEntry = classOf(name = "IngredientEntry") {
        attribute(name = "quantity", type = "Double")
        attribute(name = "unit", type = "String")
    }
    val ingredient = classOf(name = "Ingredient") {
        attribute(name = "name", type = "String")
    }
    val difficultyLevel = classOf(name = "DifficultyLevel") {
        attribute(name = "name", type = "String") // e.g., "easy", "medium", "demanding"
    }

    // A digital cookbook collects recipes that cannot exist without their cookbook.
    association(source = digitalCookbook, target = recipe) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "0..*"); role = "recipes" }
        target { multiplicity(spec = "1"); role = "cookbook" }
    }

    // Each recipe ... consists of at least one ingredient entry.
    association(source = recipe, target = ingredientEntry) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1..*"); role = "ingredientEntries" }
        target { multiplicity(spec = "1"); role = "recipe" }
    }

    // Each ingredient entry refers to exactly one ingredient from the ingredient catalog;
    // the same ingredient can appear in any number of entries.
    association(source = ingredientEntry, target = ingredient) {
        source { multiplicity(spec = "1"); role = "ingredient" }
        target { multiplicity(spec = "0..*"); role = "entries" }
    }

    // Each recipe has a difficulty level.
    association(source = recipe, target = difficultyLevel) {
        source { multiplicity(spec = "1"); role = "difficulty" }
        target { multiplicity(spec = "0..*"); role = "recipesWithThisLevel" }
    }
}

