classDiagram(name = "BoxOfficeSystem") {
    val film = classOf(name = "Film") {
        attribute(name = "title", type = "String")
    }
    val auditorium = classOf(name = "Auditorium") {
        attribute(name = "name", type = "String")
    }
    val seat = classOf(name = "Seat") {
        attribute(name = "row", type = "String")
        attribute(name = "seatNumber", type = "Int")
    }
    val screening = classOf(name = "Screening") {
        attribute(name = "startTime", type = "DateTime")
        attribute(name = "price", type = "BigDecimal")
    }
    val ticket = classOf(name = "Ticket") {
        attribute(name = "ticketId", type = "String")
        attribute(name = "purchaseTime", type = "DateTime")
    }

    association(source = screening, target = film) {
        source { multiplicity(spec = "0..*") } // A Film can have 0 or more Screenings
        target { multiplicity(spec = "1"); role = "film" } // A Screening shows exactly one Film
    }

    association(source = screening, target = auditorium) {
        source { multiplicity(spec = "0..*") } // An Auditorium can host 0 or more Screenings
        target { multiplicity(spec = "1"); role = "auditorium" } // A Screening is in exactly one Auditorium
    }

    association(source = auditorium, target = seat) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") } // A Seat belongs to exactly one Auditorium
        target { multiplicity(spec = "1..*"); role = "seats" } // An Auditorium consists of 1 or more Seats
    }

    association(source = ticket, target = screening) {
        source { multiplicity(spec = "0..*") } // A Screening can have 0 or more Tickets
        target { multiplicity(spec = "1"); role = "screening" } // A Ticket belongs to exactly one Screening
    }

    association(source = ticket, target = seat) {
        source { multiplicity(spec = "0..*") } // A Seat can be reserved by 0 or more Tickets (for different screenings)
        target { multiplicity(spec = "1"); role = "seat" } // A Ticket reserves exactly one Seat
    }
}

