classDiagram(name = "SchoolSystem") {
    val school = classOf(name = "School") {
        attribute(name = "name", type = "String")
    }
    val schoolClass = classOf(name = "Class") {
        attribute(name = "name", type = "String")
    }
    val teacher = classOf(name = "Teacher") {
        attribute(name = "name", type = "String")
    }
    val student = classOf(name = "Student") {
        attribute(name = "name", type = "String")
    }
    val lesson = classOf(name = "Lesson") {
        attribute(name = "description", type = "String")
    }
    val subject = classOf(name = "Subject") {
        attribute(name = "name", type = "String")
    }
    val reportCard = classOf(name = "ReportCard") {
        attribute(name = "year", type = "Int")
    }

    // A school is organized into classes that cannot exist without the school. (Composition)
    association(source = school, target = schoolClass) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "classes" }
    }

    // Each class has exactly one homeroom teacher, while a teacher can lead multiple classes. (Association)
    association(source = schoolClass, target = teacher) {
        source { multiplicity(spec = "0..*"); role = "classes" }
        target { multiplicity(spec = "1"); role = "homeroomTeacher" }
    }

    // Any number of students belong to a class. (Association)
    association(source = schoolClass, target = student) {
        source { multiplicity(spec = "1") } // Each student belongs to one class
        target { multiplicity(spec = "0..*"); role = "students" }
    }

    // The timetable consists of lessons, each of which brings together a subject, a teacher, and a class. (Associations)
    association(source = lesson, target = subject) {
        source { multiplicity(spec = "0..*"); role = "lessons" }
        target { multiplicity(spec = "1") }
    }
    association(source = lesson, target = teacher) {
        source { multiplicity(spec = "0..*"); role = "lessons" }
        target { multiplicity(spec = "1") }
    }
    association(source = lesson, target = schoolClass) {
        source { multiplicity(spec = "0..*"); role = "lessons" }
        target { multiplicity(spec = "1") }
    }

    // At the end of the school year, each student receives report cards that are inseparably linked to them. (Composition)
    association(source = student, target = reportCard) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "reportCards" }
    }
}

