Vehicle "1" *-- "0..*" MaintenanceRecord : hasRecords

' Association: Each trip belongs to exactly one driver
Driver "1" -- "0..*" Trip : undertakes

' Association: Each trip belongs to exactly one vehicle
Vehicle "1" -- "0..*" Trip : usedIn

' Association: Maintenance records are performed by exactly one workshop
Workshop "1" -- "0..*" MaintenanceRecord : performs

' Link Vehicle's status attribute to the VehicleStatus enum
Vehicle --> VehicleStatus

