import dev.kuml.sysml2.dsl.sysml2Model
import dev.kuml.sysml2.dsl.multiplicity.exactly
import dev.kuml.sysml2.dsl.multiplicity.range

sysml2Model(name = "RobotArmModel") {
    val base = partDef(name = "Base")
    val endEffector = partDef(name = "EndEffector")
    val joint = partDef(name = "Joint") // Abstract parent for different joint types

    // Fix for 'extends' and receiver type mismatch: Use 'general' parameter of partDef
    val revoluteJoint = partDef(name = "RevoluteJoint", general = joint.id)
    val prismaticJoint = partDef(name = "PrismaticJoint", general = joint.id)

    val robotArm = partDef(name = "RobotArm") {
        // Fix for multiplicity: Use exactly() and range() from dev.kuml.sysml2.dsl.multiplicity
        part(name = "base", typeId = base.id, multiplicity = exactly(1))
        part(name = "effector", typeId = endEffector.id, multiplicity = exactly(1))
        part(name = "joint", typeId = joint.id, multiplicity = range(1, 6)) // "between one and six joints"
    }

    bdd(name = "Robot Arm BDD") {
        include(robotArm)
        include(base)
        include(endEffector)
        include(joint)
        include(revoluteJoint)
        include(prismaticJoint)
    }
}

