import dev.kuml.sysml2.dsl.sysml2Model

sysml2Model(name = "ElectricVehicleSystem") {
    // Declare fundamental part definitions first
    val cell = partDef(name = "Cell")
    val inverter = partDef(name = "Inverter")
    val electricMotor = partDef(name = "ElectricMotor")
    val gearbox = partDef(name = "Gearbox")
    val batteryManagementSystem = partDef(name = "BatteryManagementSystem")
    val thermalManagementSystem = partDef(name = "ThermalManagementSystem")

    // Declare composite part definitions, referencing previously defined parts
    val batteryModule = partDef(name = "BatteryModule") {
        // "each module contains multiple cells"
        part(name = "cells", typeId = cell.id) // Removed isMultiple
    }

    val highVoltageBatteryPack = partDef(name = "HighVoltageBatteryPack") {
        // "The battery pack contains multiple battery modules"
        part(name = "modules", typeId = batteryModule.id) // Removed isMultiple
    }

    val drivetrain = partDef(name = "Drivetrain") {
        part(name = "batteryPack", typeId = highVoltageBatteryPack.id)
        part(name = "inverter", typeId = inverter.id)
        // "one or more electric motors"
        part(name = "motor", typeId = electricMotor.id) // Removed isMultiple
        part(name = "gearbox", typeId = gearbox.id)
    }

    // Declare the top-level vehicle system
    val vehicle = partDef(name = "Vehicle") {
        part(name = "drivetrain", typeId = drivetrain.id)
        // "the vehicle additionally has a Battery Management System (BMS) as a standalone block"
        part(name = "bms", typeId = batteryManagementSystem.id)
        // "and a thermal management system"
        part(name = "thermalSystem", typeId = thermalManagementSystem.id)
    }

    // BDD block to render all defined part definitions
    bdd(name = "Electric Vehicle System BDD") {
        include(vehicle)
        include(drivetrain)
        include(highVoltageBatteryPack)
        include(batteryModule)
        include(cell)
        include(inverter)
        include(electricMotor)
        include(gearbox)
        include(batteryManagementSystem)
        include(thermalManagementSystem)
    }
}

import dev.kuml.sysml2.dsl.sysml2Model

sysml2Model(name = "ADASModel") {
    // Abstract base block
    val sensor = partDef(name = "Sensor")

    // Specific sensor types
    val camera = partDef(name = "Camera")
    val radar = partDef(name = "Radar")
    val lidar = partDef(name = "Lidar")

    // Sensor Suite composed of various sensors
    val sensorSuite = partDef(name = "SensorSuite") {
        part(name = "cameraSensor", typeId = camera.id)
        part(name = "radarUnit", typeId = radar.id)
        part(name = "lidarScanner", typeId = lidar.id)
    }

    // Fusion and Processing Unit
    val fusionProcessingUnit = partDef(name = "FusionProcessingUnit")

    // Driver Assistance Control Unit
    val driverAssistanceControlUnit = partDef(name = "DriverAssistanceControlUnit")

    // ADAS Subsystem composed of its main components
    val adas = partDef(name = "ADAS") {
        part(name = "suite", typeId = sensorSuite.id)
        part(name = "fusionUnit", typeId = fusionProcessingUnit.id)
        part(name = "controlUnit", typeId = driverAssistanceControlUnit.id)
    }

    // Model inheritance using generalization relationships
    // Using the overload that takes UmlClassifier objects directly
    generalization(specific = camera, general = sensor)
    generalization(specific = radar, general = sensor)
    generalization(specific = lidar, general = sensor)

    // Block Definition Diagram to render all defined partDefs
    bdd(name = "ADAS Subsystem BDD") {
        include(adas)
        include(sensorSuite)
        include(fusionProcessingUnit)
        include(driverAssistanceControlUnit)
        include(sensor)
        include(camera)
        include(radar)
        include(lidar)
    }
}

import dev.kuml.sysml2.dsl.sysml2Model

sysml2Model(name = "WindTurbineModel") {
    // Abstract base block for blades
    val rotorBlade = partDef(name = "Rotor Blade", isAbstract = true)

    // Specialized blade types
    val gfrpBlade = partDef(name = "GFRP Blade", supertypeId = rotorBlade.id)
    val cfrpBlade = partDef(name = "CFRP Blade", supertypeId = rotorBlade.id)

    // Basic components
    val hub = partDef(name = "Hub")
    val gearbox = partDef(name = "Gearbox")
    val generator = partDef(name = "Generator")
    val nacelleHousing = partDef(name = "Nacelle Housing")
    val pitchControlSystem = partDef(name = "Pitch Control System")
    val yawControlSystem = partDef(name = "Yaw Control System")
    val cms = partDef(name = "Condition Monitoring System")
    val tower = partDef(name = "Tower")

    // Composite parts
    val drivetrain = partDef(name = "Drivetrain") {
        part(name = "gearbox", typeId = gearbox.id)
        part(name = "generator", typeId = generator.id)
    }

    val rotor = partDef(name = "Rotor") {
        part(name = "hub", typeId = hub.id)
        // Rotor composes with the abstract Rotor Blade type for multiple blades
        part(name = "blade", typeId = rotorBlade.id, isMultiple = true)
    }

    // Top-level Wind Turbine composition
    val windTurbine = partDef(name = "Wind Turbine") {
        part(name = "rotor", typeId = rotor.id)
        part(name = "drivetrain", typeId = drivetrain.id)
        part(name = "nacelleHousing", typeId = nacelleHousing.id)
        part(name = "pitchControl", typeId = pitchControlSystem.id)
        part(name = "yawControl", typeId = yawControlSystem.id)
        part(name = "cms", typeId = cms.id)
        part(name = "tower", typeId = tower.id)
    }

    bdd(name = "Wind Turbine BDD") {
        include(windTurbine)
        include(rotor)
        include(hub)
        include(rotorBlade)
        include(gfrpBlade)
        include(cfrpBlade)
        include(drivetrain)
        include(gearbox)
        include(generator)
        include(nacelleHousing)
        include(pitchControlSystem)
        include(yawControlSystem)
        include(cms)
        include(tower)
    }
}

import dev.kuml.sysml2.dsl.sysml2Model

sysml2Model(name = "AutonomousVehicleArchitecture") {

    // Abstract base types
    val perceptionSensor = partDef(name = "Perception Sensor", isAbstract = true)

    // Leaf components / Basic building blocks
    val gpu = partDef(name = "GPU")
    val cpu = partDef(name = "CPU")
    val dram = partDef(name = "DRAM")
    val safetyMonitoringComputer = partDef(name = "Safety Monitoring Computer")
    val hdMapUnit = partDef(name = "HD Map Unit")
    val realTimeLocalizationModule = partDef(name = "Real-time Localization Module")
    val pathPlanningModule = partDef(name = "Path Planning Module")
    val behaviorDecisionModule = partDef(name = "Behavior Decision Module")
    val steerByWireUnit = partDef(name = "Steer-by-Wire Unit")
    val brakeByWireUnit = partDef(name = "Brake-by-Wire Unit")
    val driveControl = partDef(name = "Drive Control")
    val v2xModule = partDef(name = "V2X Module")
    val telematicsModule = partDef(name = "Telematics Module")

    // Perception sensors specializing the abstract Perception Sensor
    val cameraCluster = partDef(name = "Camera Cluster") {
        specializes(perceptionSensor.id)
    }
    val radarArray = partDef(name = "Radar Array") {
        specializes(perceptionSensor.id)
    }
    val lidarScanner = partDef(name = "Lidar Scanner") {
        specializes(perceptionSensor.id)
    }
    val gpsIns = partDef(name = "GPS/INS") {
        specializes(perceptionSensor.id)
    }

    // Sub-subsystems with internal composition
    val avCompute = partDef(name = "AV Compute") {
        part(name = "gpu", typeId = gpu.id)
        part(name = "cpu", typeId = cpu.id)
        part(name = "dram", typeId = dram.id)
    }

    // Main subsystems, composing their respective components
    val perception = partDef(name = "Perception") {
        part(name = "cameraCluster", typeId = cameraCluster.id)
        part(name = "radarArray", typeId = radarArray.id)
        part(name = "lidarScanner", typeId = lidarScanner.id)
        part(name = "gpsIns", typeId = gpsIns.id)
    }

    val processingPlatform = partDef(name = "Processing Platform") {
        part(name = "avCompute", typeId = avCompute.id)
        part(name = "safetyMonitoringComputer", typeId = safetyMonitoringComputer.id)
    }

    val localizationAndMapping = partDef(name = "Localization and Mapping") {
        part(name = "hdMapUnit", typeId = hdMapUnit.id)
        part(name = "realTimeLocalizationModule", typeId = realTimeLocalizationModule.id)
    }

    val drivingDecisionAndPlanning = partDef(name = "Driving Decision and Planning") {
        part(name = "pathPlanningModule", typeId = pathPlanningModule.id)
        part(name = "behaviorDecisionModule", typeId = behaviorDecisionModule.id)
    }

    val vehicleControl = partDef(name = "Vehicle Control") {
        part(name = "steerByWireUnit", typeId = steerByWireUnit.id)
        part(name = "brakeByWireUnit", typeId = brakeByWireUnit.id)
        part(name = "driveControl", typeId = driveControl.id)
    }

    val communication = partDef(name = "Communication") {
        part(name = "v2xModule", typeId = v2xModule.id)
        part(name = "telematicsModule", typeId = telematicsModule.id)
    }

    // Top-level Autonomous Vehicle System, composing the main subsystems
    val autonomousVehicle = partDef(name = "Autonomous Vehicle") {
        part(name = "perception", typeId = perception.id)
        part(name = "processingPlatform", typeId = processingPlatform.id)
        part(name = "localizationAndMapping", typeId = localizationAndMapping.id)
        part(name = "drivingDecisionAndPlanning", typeId = drivingDecisionAndPlanning.id)
        part(name = "vehicleControl", typeId = vehicleControl.id)
        part(name = "communication", typeId = communication.id)
    }

    // BDD block to render all defined partDefs
    bdd(name = "Autonomous Vehicle System BDD") {
        include(autonomousVehicle)
        include(perception)
        include(processingPlatform)
        include(localizationAndMapping)
        include(drivingDecisionAndPlanning)
        include(vehicleControl)
        include(communication)
        include(perceptionSensor)
        include(cameraCluster)
        include(radarArray)
        include(lidarScanner)
        include(gpsIns)
        include(avCompute)
        include(gpu)
        include(cpu)
        include(dram)
        include(safetyMonitoringComputer)
        include(hdMapUnit)
        include(realTimeLocalizationModule)
        include(pathPlanningModule)
        include(behaviorDecisionModule)
        include(steerByWireUnit)
        include(brakeByWireUnit)
        include(driveControl)
        include(v2xModule)
        include(telematicsModule)
    }
}

classDiagram(name = "OnlineShop") {
    val Payment = classOf(name = "Payment") {
        isAbstract = true
        attribute(name = "amount", type = "Double")
        attribute(name = "paymentStatus", type = "String")
    }

    val Address = classOf(name = "Address") {
        attribute(name = "street", type = "String")
        attribute(name = "city", type = "String")
        attribute(name = "zipCode", type = "String")
        attribute(name = "country", type = "String")
    }
    val Category = classOf(name = "Category") {
        attribute(name = "name", type = "String")
    }
    val CreditCardPayment = classOf(name = "CreditCardPayment") {
        extends(general = Payment)
        attribute(name = "cardNumber", type = "String")
        attribute(name = "expirationDate", type = "String")
    }
    val Customer = classOf(name = "Customer") {
        attribute(name = "name", type = "String")
        attribute(name = "email", type = "String")
    }
    val Order = classOf(name = "Order") {
        attribute(name = "status", type = "String")
        attribute(name = "orderDate", type = "Date")
    }
    val OrderLineItem = classOf(name = "OrderLineItem") {
        attribute(name = "quantity", type = "Int")
        attribute(name = "unitPrice", type = "Double")
    }
    val PayPalPayment = classOf(name = "PayPalPayment") {
        extends(general = Payment)
        attribute(name = "paypalEmail", type = "String")
    }
    val Product = classOf(name = "Product") {
        attribute(name = "name", type = "String")
    }
    val ShoppingCart = classOf(name = "ShoppingCart") {
        // No explicit attributes mentioned in the description
    }
    val ShoppingCartLineItem = classOf(name = "ShoppingCartLineItem") {
        attribute(name = "quantity", type = "Int")
    }
    val Shipment = classOf(name = "Shipment") {
        attribute(name = "trackingNumber", type = "String")
    }
    val Variant = classOf(name = "Variant") {
        attribute(name = "articleNumber", type = "String")
        attribute(name = "size", type = "String")
        attribute(name = "color", type = "String")
    }

    association(source = Category, target = Category) {
        source { multiplicity(spec = "0..*"); role = "subCategories" }
        target { multiplicity(spec = "0..1"); role = "parentCategory" }
    }

    association(source = Category, target = Product) {
        source { multiplicity(spec = "0..*"); role = "products" }
        target { multiplicity(spec = "1"); role = "category" }
    }

    association(source = Product, target = Variant) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1"); role = "product" }
        target { multiplicity(spec = "1..*"); role = "variants" }
    }

    association(source = Customer, target = Address) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1"); role = "customer" }
        target { multiplicity(spec = "0..*"); role = "addresses" }
    }

    association(source = Customer, target = ShoppingCart) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1"); role = "customer" }
        target { multiplicity(spec = "0..1"); role = "activeCart" }
    }

    association(source = ShoppingCart, target = ShoppingCartLineItem) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1"); role = "shoppingCart" }
        target { multiplicity(spec = "0..*"); role = "lineItems" }
    }

    association(source = ShoppingCartLineItem, target = Variant) {
        source { multiplicity(spec = "0..*"); role = "inCarts" }
        target { multiplicity(spec = "1"); role = "variant" }
    }

    association(source = Customer, target = Order) {
        source { multiplicity(spec = "1"); role = "customer" }
        target { multiplicity(spec = "0..*"); role = "orders" }
    }

    association(source = Order, target = OrderLineItem) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1"); role = "order" }
        target { multiplicity(spec = "0..*"); role = "lineItems" }
    }

    association(source = OrderLineItem, target = Variant) {
        source { multiplicity(spec = "0..*"); role = "inOrders" }
        target { multiplicity(spec = "1"); role = "variant" }
    }

    association(source = Order, target = Payment) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1"); role = "order" }
        target { multiplicity(spec = "1"); role = "payment" }
    }

    association(source = Order, target = Shipment) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1"); role = "order" }
        target { multiplicity(spec = "0..1"); role = "shipment" }
    }

    association(source = Address, target = Shipment) {
        source { multiplicity(spec = "0..*"); role = "receivedShipments" }
        target { multiplicity(spec = "1"); role = "deliveryAddress" }
    }
}

@startuml

!define comp *--
!define agg o--
!define assoc --
!define gen <|--

class Category {
    - name: String
}

class Product {
    - name: String
    - description: String
}

class Variant {
    - articleNumber: String
    - size: String
    - color: String
    - price: Double
}

class Customer {
    - name: String
    - email: String
}

class Address {
    - street: String
    - city: String
    - zipCode: String
    - country: String
}

class ShoppingCart {
    - creationDate: Date
}

class LineItem {
    - quantity: Integer
}

class Order {
    - orderDate: Date
    - status: OrderStatus
}

class OrderLineItem {
    - quantity: Integer
    - priceAtPurchase: Double
}

abstract class Payment {
    - amount: Double
    - paymentStatus: PaymentStatus
}

class CreditCardPayment {
    - cardNumber: String
    - expiryDate: String
    - cardHolderName: String
}

class PayPalPayment {
    - payerId: String
    - transactionId: String
}

class Shipment {
    - trackingNumber: String
    - shipmentDate: Date
}

Category "0..1" parent assoc "0..*" subcategories Category
Category "1" assoc "0..*" Product : contains
Product "1" comp "1..*" Variant : has
Customer "1" comp "1..*" Address : maintains
Customer "1" comp "0..1" ShoppingCart : has
ShoppingCart "1" comp "0..*" LineItem : contains
LineItem "0..*" assoc "1" Variant : references
Customer "1" assoc "0..*" Order : places
Order "1" comp "0..*" OrderLineItem : contains
OrderLineItem "0..*" assoc "1" Variant : references
Order "1" comp "1" Payment : uses
Payment gen CreditCardPayment
Payment gen PayPalPayment
Order "1" comp "0..1" Shipment : has
Shipment "0..*" assoc "1" Address : deliversTo

@enduml

classDiagram(name = "HospitalSystem") {
    // Class Declarations
    val personalData = classOf(name = "PersonalData") {
        isAbstract = true
        attribute(name = "name", type = "String")
        attribute(name = "address", type = "String")
        attribute(name = "dateOfBirth", type = "String")
    }

    val patient = classOf(name = "Patient") {
        extends(general = personalData)
    }

    val doctor = classOf(name = "Doctor") {
        extends(general = personalData)
    }

    val nurse = classOf(name = "Nurse") {
        extends(general = personalData)
    }

    val ward = classOf(name = "Ward") {
        attribute(name = "name", type = "String")
        attribute(name = "number", type = "String")
    }

    val bed = classOf(name = "Bed") {
        attribute(name = "bedNumber", type = "String")
    }

    val inpatientStay = classOf(name = "InpatientStay") {
        attribute(name = "admissionDate", type = "String")
        attribute(name = "dischargeDate", type = "String")
        attribute(name = "admissionType", type = "String") // emergency, planned, transfer
    }

    val diagnosis = classOf(name = "Diagnosis") {
        attribute(name = "description", type = "String")
        attribute(name = "dateMade", type = "String")
    }

    val prescription = classOf(name = "Prescription") {
        attribute(name = "dateIssued", type = "String")
        attribute(name = "dosage", type = "String")
    }

    val medication = classOf(name = "Medication") {
        attribute(name = "name", type = "String")
        attribute(name = "description", type = "String")
    }

    val insuranceCompany = classOf(name = "InsuranceCompany") {
        attribute(name = "name", type = "String")
        attribute(name = "address", type = "String")
    }

    val invoice = classOf(name = "Invoice") {
        attribute(name = "amount", type = "Double")
        attribute(name = "invoiceDate", type = "String")
    }

    val billingContract = classOf(name = "BillingContract") {
        attribute(name = "contractId", type = "String")
        attribute(name = "terms", type = "String")
    }

    // Association Declarations

    // Ward consists of Beds
    association(source = ward, target = bed) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "beds" }
    }

    // Ward staffed by Nurses
    association(source = ward, target = nurse) {
        source { multiplicity(spec = "0..*"); role = "worksIn" }
        target { multiplicity(spec = "1..*"); role = "staff" }
    }

    // InpatientStay belongs to Patient
    association(source = patient, target = inpatientStay) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "stays" }
    }

    // InpatientStay occupies Bed
    association(source = bed, target = inpatientStay) {
        source { multiplicity(spec = "0..1") }
        target { multiplicity(spec = "0..1"); role = "occupies" }
    }

    // InpatientStay has Attending Physician (Doctor)
    association(source = inpatientStay, target = doctor) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "*"); role = "attendingPhysician" }
    }

    // Diagnosis belongs inseparably to Stay
    association(source = inpatientStay, target = diagnosis) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "diagnoses" }
    }

    // Diagnosis responsibility of Doctor
    association(source = diagnosis, target = doctor) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "*"); role = "responsibleDoctor" }
    }

    // Prescription issued for Diagnosis
    association(source = diagnosis, target = prescription) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "prescriptions" }
    }

    // Prescription specifying Medication
    association(source = prescription, target = medication) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "*"); role = "specifiedMedication" }
    }

    // Patient insured by InsuranceCompany
    association(source = patient, target = insuranceCompany) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "*"); role = "insuranceProvider" }
    }

    // InpatientStay generates Invoice
    association(source = inpatientStay, target = invoice) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1") }
    }

    // Invoice follows BillingContract
    association(source = invoice, target = billingContract) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "*"); role = "contractUsed" }
    }

    // Invoice submitted to InsuranceCompany
    association(source = invoice, target = insuranceCompany) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "*"); role = "submittedTo" }
    }
}

