    association(source = sensor, target = measurement) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "generates" }
    }
    association(source = testCase, target = testScenario) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1"); role = "scenario" }
