    association(source = testRun, target = testCase) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1"); role = "executedCase" }
    }
    association(source = testRun, target = testVehicle) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1"); role = "vehicle" }
    }
    association(source = testRun, target = measurement) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "collectedMeasurements" }
