        attribute(name = "termOfOffice", type = "String")
    }
    val campaign = classOf(name = "Campaign") { }
    val deployment = classOf(name = "Deployment") {
        attribute(name = "numberOfHours", type = "Int")
    }
    val payment = classOf(name = "Payment") {
        isAbstract = true
        attribute(name = "amount", type = "BigDecimal")
        attribute(name = "date", type = "Date")
    }
    val membershipFeePayment = classOf(name = "MembershipFeePayment") {
        extends(general = payment)
        attribute(name = "contributionYear", type = "Int")
    }
    val donation = classOf(name = "Donation") {
        extends(general = payment)
    }

    association(source = stateChapter, target = districtChapter) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "chapters" }
    }

    association(source = districtChapter, target = member) {
        source { multiplicity(spec = "1"); role = "hosts" }
        target { multiplicity(spec = "*"); role = "members" }
    }

    association(source = districtChapter, target = membershipApplication) {
        source { multiplicity(spec = "1"); role = "receives" }
        target { multiplicity(spec = "*"); role = "applications" }
    }

    association(source = membershipApplication, target = member) {
        source { multiplicity(spec = "1"); role = "resultsIn" }
        target { multiplicity(spec = "0..1"); role = "applicant" }
    }

    association(source = member, target = notificationContract) {
        source { multiplicity(spec = "1"); role = "has" }
        target { multiplicity(spec = "1"); role = "contractFor" }
    }

    association(source = committee, target = mandate) {
        source { multiplicity(spec = "1"); role = "awardedBy" }
        target { multiplicity(spec = "*"); role = "awards" }
    }

    association(source = mandate, target = member) {
        source { multiplicity(spec = "*"); role = "holds" }
        target { multiplicity(spec = "1"); role = "assignedTo" }
    }

    association(source = districtChapter, target = campaign) {
        source { multiplicity(spec = "1"); role = "runs" }
        target { multiplicity(spec = "*"); role = "campaigns" }
    }

    association(source = member, target = deployment) {
        source { multiplicity(spec = "1"); role = "involvedIn" }
        target { multiplicity(spec = "*"); role = "participations" }
    }

    association(source = campaign, target = deployment) {
        source { multiplicity(spec = "1"); role = "partOf" }
        target { multiplicity(spec = "*"); role = "deployments" }
    }

    association(source = member, target = payment) {
        source { multiplicity(spec = "1"); role = "originatesFrom" }
        target { multiplicity(spec = "*"); role = "payments" }
    }

    association(source = donation, target = campaign) {
        source { multiplicity(spec = "*"); role = "earmarkedFor" }
        target { multiplicity(spec = "0..1"); role = "targetCampaign" }
    }
}

@startuml
abstract class Payment {
  + amount
  + date
}
class MembershipFeePayment {
  + contributionYear
}
class Donation

class Member {
  + status: Active, Passive, Resigned
}
interface NotificationContract

class DistrictChapter
class StateChapter

class MembershipApplication {
  + applicationStatus: Received, Reviewed, Accepted, Rejected
}

class Committee
class Mandate {
  + termOfOffice
}

class Campaign
class Deployment {
  + numberOfHours
}

MembershipFeePayment <|-- Payment
Donation <|-- Payment

Member .up.|> NotificationContract

StateChapter "1" *-- "0..*" DistrictChapter : consists of
DistrictChapter "1" -- "0..*" Member : belongs to
DistrictChapter "1" -- "0..*" MembershipApplication : receives
MembershipApplication "1" -- "0..1" Member : emerges as

Committee "1" *-- "0..*" Mandate : awards
Mandate "1" -- "1" Member : awarded to

DistrictChapter "1" *-- "0..*" Campaign : runs
Member "1" -- "0..*" Deployment : participates
Campaign "1" -- "0..*" Deployment : involves

Payment "1" -- "1" Member : originates from
Donation "0..*" -- "0..1" Campaign : earmarked for
@enduml

c4Model(name = "Ride-Sharing Platform Model") {
    val passenger = person(name = "Passenger") { description = "A user requesting a ride" }
    val driver = person(name = "Driver") { description = "A user providing a ride" }

    val rideSharePlatform = softwareSystem(name = "Ride-Sharing Platform") {
        description = "A platform that matches passengers with drivers for rides."

        // Declare containers as val within the softwareSystem block to make them accessible as properties of rideSharePlatform
        val apiGateway = container(name = "API Gateway") { technology = "Kotlin/Ktor"; description = "Handles requests from passenger and driver mobile apps" }
        val matchingService = container(name = "Matching Service") { technology = "Java/Spring"; description = "Assigns suitable drivers to open ride requests" }
        val geolocationService = container(name = "Geolocation Service") { technology = "Go/gRPC"; description = "Tracks vehicle positions in real time" }
        val ridesDatabase = container(name = "Rides Database") { technology = "PostgreSQL"; description = "Stores completed rides and ride request data" }
        val paymentService = container(name = "Payment Service") { technology = "Node.js/Express"; description = "Handles billing for completed rides" }
    }

    val externalPaymentProvider = softwareSystem(name = "External Payment Service Provider") { external = true; description = "Processes actual payments" }
    val externalMapService = softwareSystem(name = "External Map Service") { external = true; description = "Provides map data and route calculation" }

    // Relationships referencing containers using their val names via the parent softwareSystem object
    relationship(source = passenger, target = rideSharePlatform.apiGateway) { technology = "Mobile App (HTTPS)"; description = "Requests and manages rides" }
    relationship(source = driver, target = rideSharePlatform.apiGateway) { technology = "Mobile App (HTTPS)"; description = "Receives ride requests and updates status" }

    relationship(source = rideSharePlatform.apiGateway, target = rideSharePlatform.matchingService) { technology = "gRPC"; description = "Forwards ride requests for matching" }
    relationship(source = rideSharePlatform.apiGateway, target = rideSharePlatform.geolocationService) { technology = "WebSocket"; description = "Updates and retrieves vehicle locations" }
    relationship(source = rideSharePlatform.matchingService, target = rideSharePlatform.geolocationService) { technology = "gRPC"; description = "Queries vehicle positions for matching" }
    relationship(source = rideSharePlatform.matchingService, target = rideSharePlatform.ridesDatabase) { technology = "JDBC"; description = "Records ride requests and matches" }
    relationship(source = rideSharePlatform.geolocationService, target = rideSharePlatform.ridesDatabase) { technology = "JDBC"; description = "Persists real-time location updates" }
    relationship(source = rideSharePlatform.paymentService, target = rideSharePlatform.ridesDatabase) { technology = "JDBC"; description = "Retrieves completed ride details for billing" }

    relationship(source = rideSharePlatform.paymentService, target = externalPaymentProvider) { technology = "REST API"; description = "Delegates payment processing" }
    relationship(source = rideSharePlatform.apiGateway, target = externalMapService) { technology = "REST API"; description = "Accesses map data for display and route calculation" }

    containerDiagram(name = "Ride-Sharing Platform - Container View") {
        system = rideSharePlatform
        showExternalSystems = true
    }
}

classDiagram(name = "UniversityModel") {
    val person = classOf(name = "Person") {
        isAbstract = true
    }
    val student = classOf(name = "Student") {
        extends(general = person)
    }
    val professor = classOf(name = "Professor") {
        extends(general = person)
    }
    val university = classOf(name = "University") {}
    val faculty = classOf(name = "Faculty") {}
    val degreeProgram = classOf(name = "DegreeProgram") {}
    val module = classOf(name = "Module") {}
    val course = classOf(name = "Course") {}
    val semester = classOf(name = "Semester") {
        attribute(name = "name", type = "String")
    }
    val enrollment = classOf(name = "Enrollment") {}
    val examinationPerformance = classOf(name = "ExaminationPerformance") {
        attribute(name = "grade", type = "String")
    }
    val exam = classOf(name = "Exam") {}

    association(source = university, target = faculty) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") } // A faculty belongs to 1 university
        target { multiplicity(spec = "1..*"); role = "faculties" } // A university has 1..* faculties
    }

    association(source = faculty, target = degreeProgram) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") } // A degree program belongs to 1 faculty
        target { multiplicity(spec = "1..*"); role = "programs" } // A faculty offers 1..* degree programs
    }

    association(source = faculty, target = professor) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") } // A professor is employed by 1 faculty
        target { multiplicity(spec = "1..*"); role = "employees" } // A faculty employs 1..* professors
    }

    association(source = degreeProgram, target = module) {
        source { multiplicity(spec = "0..*"); role = "usedInPrograms" } // A module is used in 0..* programs
        target { multiplicity(spec = "0..*"); role = "modules" } // A degree program bundles 0..* modules
    }

    association(source = module, target = course) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") } // A course belongs to 1 module
        target { multiplicity(spec = "1..*"); role = "courses" } // A module is implemented through 1..* courses
    }

    association(source = course, target = professor) {
        source { multiplicity(spec = "0..*"); role = "taughtCourses" } // A professor teaches 0..* courses
        target { multiplicity(spec = "1"); role = "taughtBy" } // A course is taught by exactly 1 professor
    }

    association(source = course, target = semester) {
        source { multiplicity(spec = "0..*"); role = "offeredCourses" } // A semester offers 0..* courses
        target { multiplicity(spec = "1"); role = "inSemester" } // A course is in exactly 1 semester
    }

    association(source = student, target = enrollment) {
        source { multiplicity(spec = "1") } // An enrollment is for 1 student
        target { multiplicity(spec = "1..*"); role = "enrollments" } // A student has 1..* enrollments
    }

    association(source = degreeProgram, target = enrollment) {
        source { multiplicity(spec = "1") } // An enrollment is for 1 degree program
        target { multiplicity(spec = "1..*"); role = "programEnrollments" } // A degree program has 1..* enrollments
    }

    association(source = student, target = examinationPerformance) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") } // An examination performance is by 1 student
        target { multiplicity(spec = "0..*"); role = "performances" } // A student completes 0..* examination performances
    }

    association(source = exam, target = examinationPerformance) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") } // An examination performance belongs to 1 exam
        target { multiplicity(spec = "1..*"); role = "examPerformances" } // An exam has 1..* examination performances
    }

    association(source = module, target = exam) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") } // An exam is assigned to 1 module
        target { multiplicity(spec = "1..*"); role = "exams" } // A module has 1..* exams
    }
}
